// Analyze script to generate visual prompt for Kling AI
const script = $('Get Approved Scripts').item.json.script_text;
const niche = $('Get Approved Scripts').item.json.niche || 'general';
const ideaText = $('Get Approved Scripts').item.json.idea_text;

// Extract key visual elements from script
function generateVisualPrompt(script, niche, idea) {
  // Map niches to visual styles
  const nicheStyles = {
    'fitness': 'modern gym, athletic people working out, energetic movements, bright lighting',
    'tech': 'futuristic interface, digital screens, modern workspace, tech gadgets',
    'finance': 'professional office, charts and graphs, business setting, clean aesthetic',
    'food': 'kitchen setting, fresh ingredients, cooking process, appetizing presentation',
    'education': 'classroom, students learning, books, bright educational environment',
    'travel': 'beautiful destinations, landmarks, scenic views, adventure',
    'fashion': 'stylish outfits, runway, urban setting, trendy aesthetics'
  };

  const baseStyle = nicheStyles[niche.toLowerCase()] || 'professional setting, clean aesthetic, modern look';

  // Generate cinematic prompt for Kling AI
  return `Cinematic B-roll footage: ${baseStyle}. Dynamic camera movements, professional lighting, 4K quality, trending on social media. Style: modern, engaging, fast-paced. Duration: ${Math.ceil(script.split(' ').length / 2.5)} seconds.`;
}

const visualPrompt = generateVisualPrompt(script, niche, ideaText);

return {
  script_id: $('Get Approved Scripts').item.json.script_id,
  visual_prompt: visualPrompt,
  duration: $('Get Approved Scripts').item.json.duration_sec || 35,
  niche: niche
};

// Upload ElevenLabs audio to Cloudinary for Hedra to access
const FormData = require('form-data');
const audioBuffer = $input.first().binary.data;

const form = new FormData();
form.append('file', audioBuffer, {
  filename: 'voice.mp3',
  contentType: 'audio/mpeg'
});
form.append('upload_preset', 'YOUR_CLOUDINARY_PRESET');
form.append('resource_type', 'video'); // Cloudinary treats audio as video

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.cloudinary.com/v1_1/YOUR_CLOUD_NAME/upload',
  body: form,
  headers: form.getHeaders()
});

return {
  audio_url: response.secure_url,
  script_id: $('Get Approved Scripts').item.json.script_id
};

// Download all generated assets
const hedraVideoUrl = $('Check Hedra Status').item.json.videoUrl;
const klingVideoUrl = $('Check Kling Status').item.json.video_url;
const scriptData = $('Get Approved Scripts').item.json;

// Download Hedra avatar video
const hedraVideo = await this.helpers.httpRequest({
  method: 'GET',
  url: hedraVideoUrl,
  encoding: 'arraybuffer'
});

// Download Kling B-roll
const klingVideo = await this.helpers.httpRequest({
  method: 'GET',
  url: klingVideoUrl,
  encoding: 'arraybuffer'
});

return {
  hedra_video: Buffer.from(hedraVideo),
  kling_video: Buffer.from(klingVideo),
  script_text: scriptData.script_text,
  script_id: scriptData.script_id,
  duration: scriptData.duration_sec
};

// Generate metadata filename
const scriptData = $('Get Approved Scripts').item.json;

const filename = `script_${scriptData.script_id}_idea_${scriptData.idea_id}_hook_${scriptData.hook_variant_id || 'null'}_transcript_${scriptData.transcript_id}_source_${scriptData.source_reel_id || 'null'}.mp4`;

return {
  filename: filename,
  script_id: scriptData.script_id,
  idea_id: scriptData.idea_id,
  hook_variant_id: scriptData.hook_variant_id,
  transcript_id: scriptData.transcript_id,
  source_reel_id: scriptData.source_reel_id,
  video_binary: $input.first().json.final_video
};
